/**********************************
 * Sum Actual Allocation's Amounts
 * 
 * by Cinthia Romero
 *********************************/
var mandatesGrid = this.PE_MANDATES;
var mandatesGridRows = Object.keys(mandatesGrid).length;
var totalActualAllocation = 0;
if (mandatesGrid != undefined && mandatesGrid != null && mandatesGridRows > 0) {
    for (var i = 0; i < mandatesGridRows; i++) {
        totalActualAllocation = totalActualAllocation + mandatesGrid[i]["PE_MANDATE_ACTUAL_ALLOCATION"];
    }
}
return totalActualAllocation;

/**
 * Sum mandate's percentages
 * 
 * by Cinthia Romero
 * modified by Elmer Orihuela
 */
var mandatesGrid = this.PE_MANDATES;
var mandatesGridRows = Object.keys(mandatesGrid).length;
var totalPercentages = 0;
if (mandatesGrid != undefined && mandatesGrid != null && mandatesGridRows > 0) {
    for (var i = 0; i < mandatesGridRows; i++) {
        totalPercentages = totalPercentages + mandatesGrid[i]["PE_MANDATE_PERCENTAGE_DEAL"];
    }
}
return totalPercentages;

let isValid = true;
let mandatesGrid = this.PE_MANDATES;
let mandatesGridRows = Object.keys(mandatesGrid).length;
if (mandatesGrid != undefined && mandatesGrid != null && mandatesGridRows > 0) {
    for (let i = 0; i < mandatesGridRows; i++) {
        if (mandatesGrid[i]["validationActualAllocation"] != '') {
            isValid = false;
        }
    }
}
return isValid;
